import hashlib
import os
import re
import subprocess

def generate_dependency_lockfile(dependencies):
    """Generate a dependency lockfile (requirements.txt with hashes) for the given dependencies."""
    # Validate input
    if not isinstance(dependencies, dict):
        raise ValueError("Invalid input type")

    # Generate hashes for each dependency
    hashes = {}
    for name, version in dependencies.items():
        hashes[name] = generate_hash(name, version)

    # Write lockfile to disk
    with open("requirements.txt", "w") as f:
        for name, version in dependencies.items():
            f.write(f"{name}=={version}\n")
        for name, hash in hashes.items():
            f.write(f"# {name}: {hash}\n")

def update_dependency_lockfile(dependencies):
    """Update the dependency lockfile (requirements.txt with hashes) for the given dependencies."""
    # Validate input
    if not isinstance(dependencies, dict):
        raise ValueError("Invalid input type")

    # Generate hashes for each dependency
    hashes = {}
    for name, version in dependencies.items():
        hashes[name] = generate_hash(name, version)

    # Update lockfile on disk
    with open("requirements.txt", "r") as f:
        lines = f.readlines()
    with open("requirements.txt", "w") as f:
        for line in lines:
            if not re.match(r"^# ", line):
                name, version = line.strip().split("==")
                if name in dependencies and version == dependencies[name]:
                    hash = generate_hash(name, version)
                    f.write(f"{name}=={version}\n")
                    f.write(f"# {name}: {hash}\n")
                else:
                    f.write(line)

def generate_hash(name, version):
    """Generate a hash for the given dependency."""
    # Validate input
    if not isinstance(name, str) or not isinstance(version, str):
        raise ValueError("Invalid input type")

    # Generate hash using SHA-256
    hash = hashlib.sha256()
    hash.update(f"{name}=={version}".encode())
    return hash.hexdigest()

def validate_dependency_lockfile():
    """Validate the dependency lockfile (requirements.txt with hashes) for consistency and integrity."""
    # Validate input
    if not os.path.exists("requirements.txt"):
        raise ValueError("Lockfile does not exist")

    # Parse lockfile
    dependencies = {}
    with open("requirements.txt", "r") as f:
        for line in f:
            if re.match(r"^# ", line):
                continue
            name, version = line.strip().split("==")
            dependencies[name] = version

    # Validate hashes
    with open("requirements.txt", "r") as f:
        for line in f:
            if re.match(r"^# ", line):
                continue
            name, version = line.strip().split("==")
            if name not in dependencies or version != dependencies[name]:
                raise ValueError("Hash mismatch")

